<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      envelopeTimezone</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;local&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// &quot;utc&quot; | &quot;local&quot; | &quot;user&quot; | IANA timezone</span></span>
